    // Delete a specific file
    async deleteFile(fileId, fileName) {
        // Check if document management is unlocked
        if (!this.documentManagementUnlocked) {
            this.showPasscodeModal();
            return;
        }

        if (!confirm(`Are you sure you want to delete "${fileName}"? This action cannot be undone.`)) {
            return;
        }

        try {
            this.showLoading('Deleting file...', `Removing ${fileName} and all associated data`);

            const response = await fetch(`/api/documents/delete/document/${fileId}`, {
                method: 'DELETE'
            });

            const result = await response.json();

            if (result.success) {
                this.showStatus(`File "${fileName}" deleted successfully`, 'success');
                // Refresh the file list
                await this.loadFiles();
                await this.loadDashboardStats();
            } else {
                this.showStatus(`Failed to delete file: ${result.message}`, 'error');
            }
        } catch (error) {
            console.error('Error deleting file:', error);
            this.showStatus('Failed to delete file. Please try again.', 'error');
        } finally {
            this.hideLoading();
        }
    }

