    async sendMessage() {
        const input = document.getElementById('chatInput');
        const message = input.value.trim();

        if (!message) return;

        // Add user message to chat
        this.addMessageToChat('user', message);
        input.value = '';

        // Show typing indicator
        this.showTypingIndicator();

        try {
            // Check if search mode is active
            const searchModeBtn = document.getElementById('searchModeBtn');
            const isSearchMode = searchModeBtn && searchModeBtn.classList.contains('active');

            let response, data;

            if (isSearchMode) {
                // Use search endpoint for search mode
                response = await fetch('/api/chatbot/search', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        query: message,
                        top_k: 10,
                        min_score: 0.5
                    })
                });

                data = await response.json();

                if (data.success) {
                    // Format search results as a response
                    const results = data.results || [];
                    let searchResponse = '';

                    if (results.length > 0) {
                        searchResponse = `Found ${results.length} relevant documents:\n\n`;
                        results.forEach((result, index) => {
                            searchResponse += `**${index + 1}. ${result.clean_pdf_name}** (Page ${result.page})\n`;
                            searchResponse += `Score: ${result.score.toFixed(3)}\n`;
                            searchResponse += `${result.content.substring(0, 200)}...\n\n`;
                        });
                    } else {
                        searchResponse = 'No relevant documents found for your search query.';
                    }

                    this.addMessageToChat('bot', searchResponse, results);
                } else {
                    this.addMessageToChat('bot', `Search Error: ${data.message}`);
                }
            } else {
                // Use chat endpoint for normal chat mode
                response = await fetch('/api/chatbot/chat', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({
                        question: message,
                        session_id: this.currentSessionId || null
                    })
                });

                data = await response.json();

                if (data.success) {
                    // Store session ID from backend response for maintaining conversation
                    if (data.session_id) {
                        this.currentSessionId = data.session_id;
                        console.log('Session ID received from backend:', this.currentSessionId);
                    }
                    this.addMessageToChat('bot', data.answer, data.sources, { heading_info: data.heading_info || null });
                } else {
                    this.addMessageToChat('bot', `Error: ${data.message}`);
                }
            }
        } catch (error) {
            console.error('Chat error:', error);
            this.addMessageToChat('bot', 'Sorry, I encountered an error. Please try again.');
        } finally {
            this.hideTypingIndicator();
        }
    }

    addMessageToChat(sender, message, sources = null, meta = null) {
        const chatMessages = document.getElementById('chatMessages');
        const messageDiv = document.createElement('div');
        const messageId = 'msg_' + Date.now() + '_' + Math.floor(Math.random() * 1000); // Unique ID for each message
        messageDiv.className = `message ${sender}-message`;
        messageDiv.id = messageId;

        const now = new Date();
        const timeString = now.toLocaleTimeString();

        // Render markdown for bot messages, keep plain text for user messages
        let formattedMessage = message;
        if (sender === 'bot' && typeof marked !== 'undefined') {
            try {
                // Configure marked for safe rendering
                marked.setOptions({
                    breaks: true,        // Convert \n to <br>
                    gfm: true,          // GitHub Flavored Markdown
                    sanitize: false,    // We trust our own AI responses
                    smartLists: true,   // Better list handling
                    smartypants: true   // Smart quotes
                });
                formattedMessage = marked.parse(message);
            } catch (error) {
                console.warn('Markdown parsing error:', error);
                formattedMessage = message; // Fallback to plain text
            }
        } else {
            // Escape HTML for user messages to prevent XSS
            formattedMessage = this.escapeHtml(message);
        }

        let sourcesHtml = '';
        let sourceToggleButton = '';
        // Optional heading info chip
        let headingChip = '';
        try {
            const headingInfo = meta && meta.heading_info;
            if (headingInfo && headingInfo.active_heading_title) {
                headingChip = `
                    <div class="heading-chip" title="Active heading context">
                        <i class="fas fa-bookmark"></i>
                        <span>${this.escapeHtml(headingInfo.active_heading_title)}</span>
                    </div>
                `;
            }
        } catch (e) { /* no-op */ }
        if (sources && sources.length > 0) {
            // Show/hide sources based on global setting
            const sourcesDisplay = this.showSources ? 'block' : 'none';
            const toggleBtnClass = this.showSources ? 'active' : '';
            const toggleBtnText = this.showSources ? 'Hide Sources' : 'Show Sources';
            const toggleIcon = this.showSources ? 'chevron-up' : 'chevron-down';

            sourceToggleButton = `
                <button class="toggle-sources-btn ${toggleBtnClass}" data-source-count="${sources.length}" onclick="window.chatbotAppInstance.toggleMessageSources('${messageId}')">
                    <i class="fas fa-${toggleIcon}"></i> ${toggleBtnText} (${sources.length})
                </button>
            `;

            sourcesHtml = `
                <div class="message-sources" style="display: ${sourcesDisplay};">
                    <h5>Sources Used (${sources.length} documents):</h5>
                    ${sources.map((source, index) => `
                        <div class="source-item">
                            <div class="source-header">
                                <span class="source-rank">#${index + 1}</span>
                                <span class="source-file">${this.escapeHtml(source.clean_pdf_name || source.pdf_name || 'Unknown Document')}</span>
                                <span class="source-page">Page ${source.page || '?'}</span>
                                <span class="source-score">Score: ${source.score.toFixed(3)}</span>
                            </div>
                            <div class="source-content">${this.escapeHtml(source.content.substring(0, 200))}${source.content.length > 200 ? '...' : ''}</div>
                        </div>
                    `).join('')}
                </div>
            `;
        }

        messageDiv.innerHTML = `
            <div class="message-avatar">
                <i class="fas fa-${sender === 'bot' ? 'robot' : 'user'}"></i>
            </div>
            <div class="message-content">
                <div class="message-header">
                    <span class="message-sender">${sender === 'bot' ? 'AI Assistant' : 'You'}</span>
                    <span class="message-time">${timeString}</span>
                </div>
                ${headingChip}
                <div class="message-text">${formattedMessage}</div>
                ${sourceToggleButton}
                ${sourcesHtml}
            </div>
        `;

        chatMessages.appendChild(messageDiv);
        chatMessages.scrollTop = chatMessages.scrollHeight;
    }

    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

